impl Solution { pub fn get_maximum_gold(mut grid: Vec<Vec<i32>>) -> i32 { fn dfs(g: &mut Vec<Vec<i32>>, r: i32, c: i32) -> i32 { if r < 0 || r >= g.len() as i32 || c < 0 || c >= g[0].len() as i32 || g[r as usize][c as usize] == 0 { return 0; } let val = g[r as usize][c as usize]; g[r as usize][c as usize] = 0; let res = val + [ (r+1, c), (r-1, c), (r, c+1), (r, c-1) ].iter().map(|&(nr, nc)| dfs(g, nr, nc)).max().unwrap(); g[r as usize][c as usize] = val; res } let (mut m, rows, cols) = (0, grid.len(), grid[0].len()); for r in 0..rows { for c in 0..cols { if grid[r][c] > 0 { m = m.max(dfs(&mut grid, r as i32, c as i32)); } } } m } }